import numpy as np

def calculate_matrix_mean(matrix: list[list[float]], mode: str) -> list[float]:
    arr = np.array(matrix)
    if mode == 'row':
        return arr.mean(axis=1).tolist()
    elif mode == 'column':
        return arr.mean(axis=0).tolist()
    else:
        raise ValueError(f"Invalid mode '{mode}'. Expected 'row' or 'column'.")
